mapper.select:
SELECT wo.warehousing_id, wo.purchase_id, wo.operator_id, wo.warehousing_time, wo.audit_status, wo.auditor_id, wo.audit_time, wo.remarks, wo.create_time, wo.update_time, wo.is_deleted, -- 【关键修改】使用 login_name operator.login_name AS operator_name, auditor.login_name AS auditor_name FROM warehousing_order wo LEFT JOIN purchase_order po ON wo.purchase_id = po.purchase_id LEFT JOIN sys_user operator ON wo.operator_id = operator.id AND operator.is_deleted = 0 LEFT JOIN sys_user auditor ON wo.auditor_id = auditor.id AND auditor.is_deleted = 0 WHERE wo.is_deleted = 0
AND po.order_no LIKE CONCAT('%', #{purchaseNo}, '%')
AND wo.audit_status = #{auditStatus}
AND wo.warehousing_time >= #{warehousingTimeStart}
AND wo.warehousing_time <= #{warehousingTimeEnd}
ORDER BY wo.create_time DESC
